export function getAreaProduct(areaSlug: string, productSlug: string): AreaProduct | undefined {
  return areaProducts.find(ap => ap.areaSlug === areaSlug && ap.productSlug === productSlug);
}

export function getAreaProducts(areaSlug: string): AreaProduct[] {
  return areaProducts.filter(ap => ap.areaSlug === areaSlug);
}
